// Parse all gathered data
const inputs = $input.all();

// Each input comes from a different branch — get by position
// We need to pull from named nodes instead
let shResponse = {};
try { shResponse = $('Saleshandy: 7-Day Stats').first().json || {}; } catch(e) { shResponse = {}; }
let mxAdscale = {};
try { mxAdscale = $('MXToolbox: adscalelab.co').first().json || {}; } catch(e) { mxAdscale = {}; }
let mxPartnerpeak = {};
try { mxPartnerpeak = $('MXToolbox: partnerpeak.co').first().json || {}; } catch(e) { mxPartnerpeak = {}; }
let mxPartnersGe = {};
try { mxPartnersGe = $('MXToolbox: partners-ge.co').first().json || {}; } catch(e) { mxPartnersGe = {}; }
let sheetRows = [];
try { sheetRows = $('Read Active Sheet').all().map(r => r.json); } catch(e) { sheetRows = []; }

// Parse Saleshandy 7-day stats
let sent = 0, opened = 0, replied = 0, bounced = 0;
let openRate = 0, replyRate = 0, bounceRate = 0;
let saleshandyAvailable = true;

try {
  const data = shResponse.data || shResponse.analytics || shResponse;
  sent = data.sent || data.emailsSent || 0;
  opened = data.opened || data.emailsOpened || 0;
  replied = data.replied || data.emailsReplied || 0;
  bounced = data.bounced || data.emailsBounced || 0;

  if (sent > 0) {
    openRate = (opened / sent) * 100;
    replyRate = (replied / sent) * 100;
    bounceRate = (bounced / sent) * 100;
  }

  if (!shResponse.data && !shResponse.analytics && sent === 0) {
    saleshandyAvailable = false;
  }
} catch (e) {
  saleshandyAvailable = false;
}

// Parse blacklist status
const checkBlacklist = (response, domain) => {
  try {
    if (!response || response.error || response.Failed) {
      return { domain, status: 'CHECK_FAILED', isBlacklisted: false };
    }
    // MXToolbox returns Failed array if blacklisted
    const failed = response.Failed || [];
    const isBlacklisted = Array.isArray(failed) && failed.length > 0;
    return { domain, status: isBlacklisted ? 'BLACKLISTED' : 'CLEAN', isBlacklisted };
  } catch (e) {
    return { domain, status: 'CHECK_FAILED', isBlacklisted: false };
  }
};

const domains = [
  checkBlacklist(mxAdscale, 'adscalelab.co'),
  checkBlacklist(mxPartnerpeak, 'partnerpeak.co'),
  checkBlacklist(mxPartnersGe, 'partners-ge.co')
];

const mxtoolboxAvailable = !domains.every(d => d.status === 'CHECK_FAILED');
const anyBlacklisted = domains.some(d => d.isBlacklisted);

// Parse sheet: leads added in past 7 days
const sevenDaysAgo = new Date(Date.now() - 7 * 86400000);
const leadsThisWeek = sheetRows.filter(r => {
  const dateAdded = new Date(r.date_added || '');
  return dateAdded >= sevenDaysAgo;
}).length;

const totalActive = sheetRows.filter(r => r.status === 'Active').length;

// Evaluate thresholds
const issues = [];
let overallHealth = 'HEALTHY';

// Bounce rate
if (bounceRate > 5) {
  issues.push('CRITICAL: Bounce rate >5% — PAUSE ALL SENDING');
  overallHealth = 'CRITICAL';
} else if (bounceRate > 3) {
  issues.push('WARNING: Bounce rate >3%');
  if (overallHealth === 'HEALTHY') overallHealth = 'WARNING';
}

// Open rate
if (openRate < 10 && saleshandyAvailable && sent > 0) {
  issues.push('CRITICAL: Open rate <10%');
  overallHealth = 'CRITICAL';
} else if (openRate < 15 && saleshandyAvailable && sent > 0) {
  issues.push('WARNING: Open rate <15%');
  if (overallHealth === 'HEALTHY') overallHealth = 'WARNING';
}

// Reply rate
if (replyRate < 1 && saleshandyAvailable && sent > 0) {
  issues.push('WARNING: Reply rate <1%');
  if (overallHealth === 'HEALTHY') overallHealth = 'WARNING';
}

// Domain blacklist
if (anyBlacklisted) {
  const blacklistedDomains = domains.filter(d => d.isBlacklisted).map(d => d.domain).join(', ');
  issues.push(`CRITICAL: Domain(s) blacklisted: ${blacklistedDomains}`);
  overallHealth = 'CRITICAL';
}

// Leads per week
if (leadsThisWeek < 5) {
  issues.push('CRITICAL: Fewer than 5 leads added this week');
  overallHealth = 'CRITICAL';
} else if (leadsThisWeek < 10) {
  issues.push('WARNING: Fewer than 10 leads added this week');
  if (overallHealth === 'HEALTHY') overallHealth = 'WARNING';
}

const bounceStatus = bounceRate > 5 ? 'CRITICAL' : bounceRate > 3 ? 'WARNING' : 'OK';
const openStatus = openRate < 10 ? 'CRITICAL' : openRate < 15 ? 'WARNING' : 'OK';
const leadsStatus = leadsThisWeek < 5 ? 'CRITICAL' : leadsThisWeek < 10 ? 'WARNING' : 'OK';

// Format domain health lines
const domainLines = domains.map(d => `│ ${d.domain}: [${d.status}]`).join('\n');

// Build report
let campaignSection = '';
if (!saleshandyAvailable) {
  campaignSection = '│ Saleshandy API unavailable';
} else {
  campaignSection = [
    `│ Sent: ${sent} | Opened: ${opened} (${openRate.toFixed(1)}%) | Replied: ${replied} (${replyRate.toFixed(1)}%)`,
    `│ Bounced: ${bounced} (${bounceRate.toFixed(1)}%) | [${bounceStatus}]`
  ].join('\n');
}

let blacklistSection = '';
if (!mxtoolboxAvailable) {
  blacklistSection = '│ Blacklist check unavailable';
} else {
  blacklistSection = domainLines;
}

const actionNeeded = issues.length === 0 ? 'None' : issues.join('\n│   ');

const report = [
  '┌─ GE Outreach Weekly Health Check ────────',
  `│ Status: [${overallHealth}]`,
  '│',
  '│ 7-Day Metrics',
  campaignSection,
  '│',
  '│ Domain Health',
  blacklistSection,
  '│',
  '│ Pipeline',
  `│ Leads added this week: ${leadsThisWeek} [${leadsStatus}]`,
  `│ Total active prospects: ${totalActive}`,
  '│',
  `│ Action needed: ${actionNeeded}`,
  '└──────────────────────────────────────────'
].join('\n');

return [{
  json: {
    report,
    overallHealth,
    isCritical: overallHealth === 'CRITICAL'
  }
}];

